                    {["200 transcriptions / month", "Enhanced AI accuracy", "Batch upload & process", "AI-generated outlines", "Export to Google Drive", "Save & organize in folders", "Priority processing"].map((f, i) => (
                      <div key={i} style={{ display: "flex", alignItems: "center", gap: 8 }}>
                        <span style={{ color: C.gold, fontWeight: 700, fontSize: 14 }}>&#10003;</span><span>{f}</span>
                      </div>
                    ))}
